components.calculateValue:
const blockchain = data.blockchainType;
const sourceKey = `ArrayWalletList${blockchain}`;
const selectedList = data[sourceKey];

value = (Array.isArray(selectedList) && selectedList.length)
  ? selectedList.map(row => ({
      wallet: row.wallet || ''
    }))
  : [{ wallet: '' }];

data.custom:
var wallets = JSON.parse(data.sid.wallets || '[]');
// console.log(wallets);
values = wallets.filter(function(w) { return w.type === data.blockchainType; }).map(function(w) {
    var addr = w.address;
  var short = addr.substring(0,6) + '...' + addr.substring(addr.length - 4);
  return { label: w.label, value: w.address, shortAddress: short };
});

validate.custom:
let v = (data.paymentPreferences && data.paymentPreferences.ibanRaw) ? data.paymentPreferences.ibanRaw : '';
v = v.replace(/[^A-Za-z0-9]/g, "");
let match = v.match(/^[A-Z]{2}[0-9]{2}[A-Za-z0-9]{11,30}$/)
if (v.length==0) {
 valid = ""
} else if (v.length < 15) {
 valid = "The IBAN should be at least 15 characters."
} else if (v.length > 34) {
 valid = "The IBAN should be at most 34 characters."
} else if (!match) {
 valid = "Please check your IBAN. It should start with a 2 letter country code and 2 numbers. Examples: IE12, CY 43, LU 28"
} else {
 valid = true
}

